+    if ((status & 0x7f) == 0) {
+        return .{ .exit_code = @intCast((status >> 8) & 0xff), .signal = null };
+    }
+    const sig: u8 = @intCast(status & 0x7f);
+    return .{ .exit_code = 128 + sig, .signal = sig };
+}

