+        if (name[cmd_name.len] == ' ' and name[cmd_name.len + 1] == '(' and name[name.len - 1] == ')') {
+            return true;
+        }
+    }
+    return false;
+}
+
+pub fn sanitizeTitle(allocator: std.mem.Allocator, title: []const u8) ![]u8 {
+    var list = std.ArrayList(u8).init(allocator);
+    errdefer list.deinit();
