+    var count: usize = 0;
+    while (it.nextCodepointSlice()) |slice| {
+        const cp = std.unicode.utf8Decode(slice) catch continue;
+        if (cp >= 32 and cp != 127 and (cp < 128 or cp > 159)) {
+            try list.appendSlice(slice);
+            count += 1;
+            if (count >= 256) break;
+        }
+    }
+
+    return list.toOwnedSlice();
+}

